import { getPlanEndDate } from "../utils/membership";

const STORAGE_KEY = "pulsefit-mock-db-v1";

function formatDate(date) {
  return date.toISOString().split("T")[0];
}

function daysFromToday(days) {
  const date = new Date();
  date.setHours(0, 0, 0, 0);
  date.setDate(date.getDate() + days);
  return formatDate(date);
}

function createDefaultCustomers() {
  return [
    {
      gymId: "GYM001",
      customerId: 1,
      fullName: "Sarah Khan",
      phone: "9876543210",
      age: 27,
      plan: "1 Month",
      amountPaid: 1500,
      planStart: daysFromToday(-5),
      planEnd: getPlanEndDate(daysFromToday(-5), "1 Month"),
      lastAttended: daysFromToday(0),
      status: "Active"
    },
    {
      gymId: "GYM001",
      customerId: 2,
      fullName: "Arjun Mehta",
      phone: "9811122233",
      age: 31,
      plan: "1 Month",
      amountPaid: 1600,
      planStart: daysFromToday(-28),
      planEnd: getPlanEndDate(daysFromToday(-28), "1 Month"),
      lastAttended: daysFromToday(-1),
      status: "Active"
    },
    {
      gymId: "GYM001",
      customerId: 3,
      fullName: "Neha Reddy",
      phone: "9822233344",
      age: 24,
      plan: "1 Month",
      amountPaid: 1400,
      planStart: daysFromToday(-40),
      planEnd: getPlanEndDate(daysFromToday(-40), "1 Month"),
      lastAttended: daysFromToday(-10),
      status: "Active"
    },
    {
      gymId: "GYM001",
      customerId: 4,
      fullName: "Vikram Singh",
      phone: "9833344455",
      age: 29,
      plan: "3 Months",
      amountPaid: 4200,
      planStart: daysFromToday(-20),
      planEnd: getPlanEndDate(daysFromToday(-20), "3 Months"),
      lastAttended: "",
      status: "Active"
    }
  ];
}

function createDefaultDatabase() {
  return {
    gyms: [
      {
        gymId: "GYM001",
        email: "admin@gmail.com",
        password: "1234"
      }
    ],
    customers: createDefaultCustomers(),
    attendances: []
  };
}

function readDatabase() {
  const raw = localStorage.getItem(STORAGE_KEY);

  if (!raw) {
    const database = createDefaultDatabase();
    writeDatabase(database);
    return database;
  }

  try {
    return JSON.parse(raw);
  } catch (error) {
    const database = createDefaultDatabase();
    writeDatabase(database);
    return database;
  }
}

function writeDatabase(database) {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(database));
}

function buildResponse(data) {
  return Promise.resolve({ data });
}

function buildError(status, message) {
  return Promise.reject({
    response: {
      status,
      data: { message }
    }
  });
}

function getGymIdFromToken() {
  const token = localStorage.getItem("token");

  if (!token || !token.startsWith("mock-token:")) {
    return null;
  }

  return token.replace("mock-token:", "");
}

function requireAuth() {
  const gymId = getGymIdFromToken();

  if (!gymId) {
    throw {
      response: {
        status: 401,
        data: { message: "No token" }
      }
    };
  }

  return gymId;
}

function getNotifications(customers) {
  const today = new Date();
  today.setHours(0, 0, 0, 0);

  return customers
    .map((customer) => {
      const planEnd = new Date(`${customer.planEnd}T00:00:00`);
      const diff =
        (planEnd.getTime() - today.getTime()) / (1000 * 60 * 60 * 24);

      if (diff < 0) {
        return { name: customer.fullName, type: "expired" };
      }

      if (diff <= 3) {
        return { name: customer.fullName, type: "expiring" };
      }

      return null;
    })
    .filter(Boolean);
}

const mockApi = {
  get(path) {
    if (path === "/seed") {
      const database = createDefaultDatabase();
      writeDatabase(database);
      localStorage.removeItem("token");
      return buildResponse("Demo user created");
    }

    if (path === "/customers") {
      try {
        const gymId = requireAuth();
        const database = readDatabase();
        const customers = database.customers.filter(
          (customer) => customer.gymId === gymId
        );
        return buildResponse(customers);
      } catch (error) {
        return Promise.reject(error);
      }
    }

    if (path === "/notifications") {
      try {
        const gymId = requireAuth();
        const database = readDatabase();
        const customers = database.customers.filter(
          (customer) => customer.gymId === gymId
        );
        return buildResponse(getNotifications(customers));
      } catch (error) {
        return Promise.reject(error);
      }
    }

    return buildError(404, "Mock route not found.");
  },

  post(path, payload) {
    if (path === "/login") {
      const database = readDatabase();
      const gym = database.gyms.find((item) => item.email === payload.email);

      if (!gym || gym.password !== payload.password) {
        return buildError(401, "Invalid");
      }

      return buildResponse({ token: `mock-token:${gym.gymId}` });
    }

    if (path === "/customers") {
      try {
        const gymId = requireAuth();
        const database = readDatabase();
        const gymCustomers = database.customers.filter(
          (customer) => customer.gymId === gymId
        );
        const today = formatDate(new Date());

        const customer = {
          gymId,
          customerId: gymCustomers.length + 1,
          fullName: payload.fullName,
          phone: payload.phone,
          age: payload.age,
          plan: payload.plan,
          amountPaid: payload.amountPaid,
          planStart: today,
          planEnd: getPlanEndDate(today, payload.plan),
          lastAttended: "",
          status: "Active"
        };

        database.customers.push(customer);
        writeDatabase(database);

        return buildResponse(customer);
      } catch (error) {
        return Promise.reject(error);
      }
    }

    if (path === "/customers/attendance") {
      try {
        const gymId = requireAuth();
        const database = readDatabase();
        const customer = database.customers.find(
          (item) =>
            item.gymId === gymId &&
            item.customerId === Number(payload.customerId)
        );

        if (!customer) {
          return buildError(404, "Not found");
        }

        const today = formatDate(new Date());
        customer.lastAttended = today;
        database.attendances.push({
          gymId,
          customerId: customer.customerId,
          date: today
        });
        writeDatabase(database);

        return buildResponse(customer);
      } catch (error) {
        return Promise.reject(error);
      }
    }

    return buildError(404, "Mock route not found.");
  }
};

export default mockApi;
